1	import { describe, it, expect } from "vitest";
2	import { quote, claim, runScenario } from "./claim-office.js";
3	
4	describe("Claim Office", () => {
5	  describe("Quote - Base premiums", () => {
6	    it("should return 5G for an empty item list (only processing fee)", () => {
7	      const result = quote({ customer: { years: 0 }, items: [] }, { isFollowUp: false });
8	      expect(result).toEqual({ premium: 5 });
9	    });
10	    it.todo("should return 115G for a single sword (100G base + 10G first insurance + 5G fee)");
11	    it.todo("should return 71G for a single amulet (60G base + 6G first insurance + 5G fee)");
12	    it.todo("should return 93G for a single staff (80G base + 8G first insurance + 5G fee)");
13	    it.todo("should return 49G for a single potion (40G base + 4G first insurance + 5G fee)");
14	  });
15	
16	  describe("Quote - Component pricing", () => {
17	    it.todo("should return 2 runes as 50G base premium (2 x 25G)");
18	    it.todo("should return 3 runes as 60G base premium (block of 3 alike applies)");
19	    it.todo("should return 4 runes as 100G base premium (no block — block requires exactly 3)");
20	    it.todo("should return 7 runes as 175G base premium (7 x 25G, no block)");
21	    it.todo("should return 2 runes + 1 moonstone as 75G base premium (no block: different types)");
22	    it.todo("should return 3 runes + 3 moonstones as 120G base premium (two separate blocks: 60G + 60G)");
23	  });
24	
25	  describe("Quote - Item-level modifiers", () => {
26	    it.todo("should add 50% curse surcharge to a cursed sword (100G + 50G = 150G before policy modifiers)");
27	    it.todo("should add 30% high-enchantment surcharge for sword with enchantment 5 (100G + 30G = 130G before policy modifiers)");
28	    it.todo("should not add high-enchantment surcharge for sword with enchantment 4 (100G before policy modifiers)");
29	    it.todo("should add both cursed and high-enchantment surcharges for cursed sword ench 5 (100G + 50G + 30G = 180G before policy modifiers)");
30	    it.todo("should apply cursed surcharge only to the cursed item: cursed sword + plain amulet = 210G before policy modifiers and fee");
31	  });
32	
33	  describe("Quote - Policy-level modifiers", () => {
34	    it.todo("should apply 20% loyalty discount for customer with >= 2 years");
35	    it.todo("should apply loyalty discount for customer with exactly 2 years");
36	    it.todo("should not apply loyalty discount for customer with 1 year");
37	    it.todo("should always apply 10% first insurance surcharge on every quote");
38	    it.todo("should apply 15% follow-up contract discount on second quote in scenario");
39	    it.todo("should apply policy-level modifiers to the sum of all item premiums (after item-level modifiers)");
40	  });
41	
42	  describe("Quote - Rounding", () => {
43	    it.todo("should round premium up (ceil) — a calculation yielding 197.5G becomes 198G");
44	    it.todo("should keep intermediates as fractions and only round the final premium");
45	  });
46	
47	  describe("Quote - Integration: Newcomer cursed sword", () => {
48	    it.todo("should return 165G for newcomer (0 years) with cursed sword (steel, ench 3): 100 base + 50 curse + 10 first insurance = 160 + 5 fee = 165G");
49	  });
50	
51	  describe("Quote - Integration: Long-standing customer second contract", () => {
52	    it.todo("should return 160G for 3-year customer on second quote with cursed sword (steel, ench 7): 100 base + 50 curse + 30 high ench - 20 loyalty + 10 first insurance - 15 follow-up = 155 + 5 fee = 160G");
53	  });
54	
55	  describe("Claim - Standard reimbursement", () => {
56	    it.todo("should return payout 400G for regular sword (steel, ench 3) with 500G damage (full reimbursement minus 100G deductible)");
57	    it.todo("should return payout 100G for rune with 200G damage (full reimbursement minus 100G deductible; no special clauses)");
58	  });
59	
60	  describe("Claim - Deductible per damage event", () => {
61	    it.todo("should apply 100G deductible per damaged item: sword 500G + amulet 300G = payout 600G (400 + 200)");
62	  });
63	
64	  describe("Claim - Enchantment and dragon material clauses", () => {
65	    it.todo("should return payout 400G for dragon-material sword ench 9, damage 1000G (both clauses: 50% wins, 500 - 100 deductible)");
66	    it.todo("should return payout 700G for dragon-material sword ench 5, damage 800G (only dragon clause: 800 - 100 deductible)");
67	    it.todo("should return payout 400G for steel sword ench 9, damage 1000G (only high-ench clause: 50% = 500, minus 100 deductible)");
68	    it.todo("should return payout 400G for dragon-material sword ench 8, damage 1000G (threshold at 8: both clauses, 50% wins, 500 - 100)");
69	  });
70	
71	  describe("Claim - Payout rounding", () => {
72	    it.todo("should round payout down (floor) — a calculation yielding 350.5G becomes 350G");
73	  });
74	
75	  describe("Claim - Cap and insurance sum", () => {
76	    it.todo("should compute insurance sum 2000G and cap 4000G for 2 swords");
77	    it.todo("should compute insurance sum 1600G and cap 3200G for sword + amulet");
78	    it.todo("should base cap on unmodified insurance value — cursed sword cap = 2000G");
79	    it.todo("should compute insurance sum 1750G for sword + 3 runes (block discount affects premium only, not insurance sum)");
80	    it.todo("should exhaust cap across two claims: first claim 1500G damage -> payout 1400G (remaining 600G), second claim 1500G damage -> payout 600G (remaining 0G)");
81	  });
82	
83	  describe("Claim - Multiple items of same type", () => {
84	    it.todo("should treat 2 sword damage entries each with own deductible when policy covers 2 swords");
85	    it.todo("should reject with error when damages contain more entries of a type than the policy covers (2 sword damages, 1 sword insured)");
86	  });
87	
88	  describe("Error handling", () => {
89	    it.todo("should exit with non-zero status and stderr error for unknown item type in quote (e.g. 'broomstick')");
90	    it.todo("should exit with non-zero status and stderr error when claim references item not in policy");
91	    it.todo("should exit with non-zero status and stderr error for negative damage amount");
92	  });
93	
94	  describe("CLI interface", () => {
95	    it.todo("should read JSON scenario from stdin and write JSON results to stdout");
96	    it.todo("should output quote result with premium as integer");
97	    it.todo("should output claim result with payout and remainingCap as integers");
98	    it.todo("should exit with non-zero code and write error to stderr for invalid input, with no results on stdout");
99	  });
100	});
